      make ?lastUpdatedDateTime ?creationDateTime ?storageLocation ?numTurns
        ?roleArn ?status ?modality ?description ?testSetName ?testSetId ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
